const WORD_LIST = Object.keys(WORDS);

// A larger rotation for "today's word" — mixes the curated words above
// (which get the full etymology treatment) with everyday interesting words
// whose data is pulled live from the dictionary API.
const DAILY_POOL = [
  ...WORD_LIST,
  "luminous", "resilience", "tranquil", "whimsical", "solitude",
  "wanderlust", "melancholy", "euphoria", "verdant", "effervescent",
  "labyrinth", "ineffable",
  "radiant", "serene", "wistful", "exuberant", "meticulous",
  "enigma", "paradox", "vivid", "tenacious", "eloquent",
  "candid", "lucid", "pristine", "sublime",
  "harmony", "curiosity", "kindred",
  "zeal", "fortitude", "grace", "clarity",
];

function wordOfDayKey() {
  const start = new Date(new Date().getFullYear(), 0, 0);
  const diff = new Date() - start;
  const dayOfYear = Math.floor(diff / 86400000);
  return DAILY_POOL[dayOfYear % DAILY_POOL.length];
}

function EtymologyTimeline({ stages }) {
  const [open, setOpen] = useState(0);
  return (
    <div className="etyWrap">
      <div className="etyNodes">
        {stages.map((s, i) => (
          <React.Fragment key={i}>
            <button
              className={`etyNode ${open === i ? "isOpen" : ""}`}
              onClick={() => setOpen(i)}
              aria-expanded={open === i}
            >
              <span className="etyTag">{s.tag}</span>
              <span className="etyDot" />
            </button>
            {i < stages.length - 1 && <span className="etySpacer" />}
          </React.Fragment>
        ))}
      </div>
      <div className="etyDetail">
        <p className="etyLabel">{stages[open].label}</p>
        <p className="etyText">{stages[open].detail}</p>
      </div>
      <style>{`
        .etyWrap{ margin-top:4px; }
        .etyNodes{ display:flex; align-items:center; }
        .etySpacer{ flex:1; height:1px; background:#E2D9CD; margin:0 2px 22px; }
        .etyNode{
          background:none; border:none; cursor:pointer; display:flex; flex-direction:column-reverse;
          align-items:center; gap:9px; padding:0; font-family:'Inter', sans-serif;
          font-size:11px; letter-spacing:0.06em; text-transform:uppercase; color:#A79E8F;
          transition:color .15s ease;
        }
        .etyNode:hover{ color:#2B2A28; }
        .etyDot{
          width:9px; height:9px; border-radius:50%; background:#FBF4E9;
          border:1.5px solid #C9B9AE; transition:all .15s ease;
        }
        .etyNode.isOpen .etyDot{ background:#96A2B4; border-color:#96A2B4; transform:scale(1.3); }
        .etyNode.isOpen{ color:#2B2A28; font-weight:600; }
        .etyDetail{
          margin-top:22px; padding-top:4px;
        }
        .etyLabel{ font-family:'Louize', 'Bodoni Moda', serif; font-style:italic; font-weight:600; font-size:22px; color:#2B2A28; margin:0 0 6px; }
        .etyText{ font-family:'Cormorant Garamond', serif; font-size:16.5px; line-height:1.7; color:#615A4F; margin:0; max-width:46ch; }
        @media (prefers-reduced-motion: reduce){ .etyNode, .etyDot{ transition:none; } }
      `}</style>
    </div>
  );
}

function speakWord(word) {
  if (typeof window === "undefined" || !window.speechSynthesis) return;
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(word);
  utterance.rate = 0.9;
  utterance.pitch = 1;
  window.speechSynthesis.speak(utterance);
}

async function fetchRelatedWords(word) {
  try {
    const res = await fetch(`https://api.datamuse.com/words?rel_trg=${encodeURIComponent(word)}&max=6`);
    if (!res.ok) return [];
    const data = await res.json();
    return data.map((d) => d.word).filter(Boolean).slice(0, 6);
  } catch (err) {
    return [];
  }
}

async function fetchDictionaryData(word) {
  const key = word.trim().toLowerCase();
  const [res, related] = await Promise.all([
    fetch(`https://api.dictionaryapi.dev/api/v2/entries/en/${encodeURIComponent(key)}`),
    fetchRelatedWords(key),
  ]);
  if (!res.ok) throw new Error("not found");
  const data = await res.json();
  const first = data[0];
  const allMeanings = data.flatMap((d) => d.meanings || []);
  const pos = allMeanings[0]?.partOfSpeech || "—";
  const definitions = allMeanings
    .flatMap((m) => m.definitions || [])
    .map((d) => d.definition)
    .filter(Boolean)
    .slice(0, 4);
  const exampleDef = allMeanings.flatMap((m) => m.definitions || []).find((d) => d.example);
  const synonymsSet = new Set();
  allMeanings.forEach((m) => {
    (m.synonyms || []).forEach((s) => synonymsSet.add(s));
    (m.definitions || []).forEach((d) => (d.synonyms || []).forEach((s) => synonymsSet.add(s)));
  });
  const phonetic = first.phonetic || (first.phonetics || []).find((p) => p.text)?.text || "";

  return {
    word: first.word || key,
    ipa: phonetic || "—",
    pos,
    definitions: definitions.length ? definitions : ["No definition found for this word."],
    example: exampleDef ? exampleDef.example : "No example sentence available for this word yet.",
    etymology: [],
    related: related.filter((w) => w.toLowerCase() !== key),
    synonyms: Array.from(synonymsSet).slice(0, 6),
    live: true,
  };
}

async function fetchLiveEntry(word, setLiveEntry, setLoading, setFetchError) {
  const key = word.trim().toLowerCase();
  if (!key) return;
  setLoading(true);
  setFetchError("");
  setLiveEntry(null);
  try {
    const entryData = await fetchDictionaryData(key);
    setLiveEntry(entryData);
  } catch (err) {
    setFetchError(key);
  } finally {
    setLoading(false);
  }
}

export default function App() {
  const [query, setQuery] = useState("");
  const [active, setActive] = useState(WORD_LIST[0]);
  const [showSuggest, setShowSuggest] = useState(false);
  const [liveEntry, setLiveEntry] = useState(null);
  const [loading, setLoading] = useState(false);
  const [fetchError, setFetchError] = useState("");
  const [dailyPreview, setDailyPreview] = useState(null);
  const inputRef = useRef(null);

  React.useEffect(() => {
    const dayKey = wordOfDayKey();
    if (WORD_LIST.includes(dayKey)) {
      setDailyPreview({ word: dayKey, def: WORDS[dayKey].definitions[0] });
      setActive(dayKey);
    } else {
      setDailyPreview({ word: dayKey, def: "Loading today's word…" });
      fetchDictionaryData(dayKey)
        .then((data) => {
          setDailyPreview({ word: dayKey, def: data.definitions[0] });
          setLiveEntry(data);
        })
        .catch(() => {
          setDailyPreview({ word: dayKey, def: "See today's word on Etymonline instead." });
        });
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const suggestions = useMemo(() => {
    if (!query.trim()) return [];
    return WORD_LIST.filter((w) => w.startsWith(query.trim().toLowerCase())).slice(0, 6);
  }, [query]);

  const entry = liveEntry || WORDS[active];
  const notFound = Boolean(fetchError) && !loading;

  function go(w) {
    setLiveEntry(null);
    setFetchError("");
    setActive(w);
    setQuery("");
    setShowSuggest(false);
  }

  function openDailyWord() {
    if (!dailyPreview) return;
    if (WORD_LIST.includes(dailyPreview.word)) {
      go(dailyPreview.word);
    } else {
      fetchLiveEntry(dailyPreview.word, setLiveEntry, setLoading, setFetchError);
    }
  }

  function onSubmit(e) {
    e.preventDefault();
    const q = query.trim().toLowerCase();
    if (!q) return;
    if (WORD_LIST.includes(q)) {
      go(q);
    } else {
      setShowSuggest(false);
      fetchLiveEntry(q, setLiveEntry, setLoading, setFetchError);
    }
  }

  return (
    <div className="page">
      <div className="grain" aria-hidden="true" />
      <div className="stripeBar top" aria-hidden="true" />
      <header className="header">
        <span className="brand">commonplace</span>
        <form className="searchForm" onSubmit={onSubmit} autoComplete="off">
          <input
            ref={inputRef}
            value={query}
            onChange={(e) => { setQuery(e.target.value); setShowSuggest(true); }}
            onFocus={() => setShowSuggest(true)}
            onBlur={() => setTimeout(() => setShowSuggest(false), 120)}
            placeholder="Search"
            aria-label="Search for a word"
          />
          {showSuggest && suggestions.length > 0 && (
            <ul className="suggest">
              {suggestions.map((w) => (
                <li key={w}><button type="button" onMouseDown={() => go(w)}>{w}</button></li>
              ))}
            </ul>
          )}
        </form>
      </header>

      <div className="dayStrip">
        <span className="dayStripLabel">today's word</span>
        <button className="dayStripWord" onClick={openDailyWord}>
          {dailyPreview ? dailyPreview.word : "…"}
        </button>
        <span className="dayStripDot">·</span>
        <span className="dayStripDef">{dailyPreview ? dailyPreview.def : "Loading…"}</span>
      </div>

      <div className="sectionDivider" />

      <main className="layout">
        <section className="main">
          {loading ? (
            <div className="empty">
              <p className="emptyTitle">Looking it up…</p>
              <p className="emptyBody">Checking the dictionary for this word.</p>
            </div>
          ) : notFound ? (
            <div className="empty">
              <p className="emptyTitle">No entry found</p>
              <p className="emptyBody">"{fetchError}" isn't in the dictionary. Try another word.</p>
            </div>
          ) : (
            <article className="entry" key={entry.word}>
              <p className="pos">{entry.pos}</p>
              <h1>{entry.word}</h1>
              <p className="ipa">
                {entry.ipa}
                <button
                  className="playBtn"
                  onClick={() => speakWord(entry.word)}
                  aria-label={`Hear how to pronounce ${entry.word}`}
                  title="Hear pronunciation"
                >
                  <svg viewBox="0 0 24 24" width="13" height="13" aria-hidden="true">
                    <path d="M8 5v14l11-7z" fill="currentColor" />
                  </svg>
                </button>
              </p>

              <ol className="defs">
                {entry.definitions.map((d, i) => <li key={i}>{d}</li>)}
              </ol>
              {entry.live && <p className="apiNote">Definition via the Free Dictionary API</p>}

              <div className="synonyms">
                <div className="synonymsHead">
                  <span className="synonymsLabel">synonyms</span>
                  <a
                    className="externalLink"
                    href={`https://www.thesaurus.com/browse/${encodeURIComponent(entry.word)}`}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    More on Thesaurus.com ↗
                  </a>
                </div>
                {entry.synonyms.length > 0 ? (
                  <div className="chips">
                    {entry.synonyms.map((s) => (
                      <button
                        key={s}
                        className={WORD_LIST.includes(s) ? "chip isLink" : "chip"}
                        onClick={() => WORD_LIST.includes(s) && go(s)}
                      >
                        {s}
                      </button>
                    ))}
                  </div>
                ) : (
                  <p className="noSynonyms">{entry.word} stands alone — no true synonyms exist.</p>
                )}
              </div>

              <div className="practice">
                <span className="practiceLabel">in practice</span>
                <p className="example">
                  <span className="exampleMark">“</span>{entry.example}<span className="exampleMark">”</span>
                </p>
              </div>

              <div className="divider" />

              <div className="etymologyHead">
                <h2 className="etymologyHeading">Etymology</h2>
                <a
                  className="externalLink"
                  href={`https://www.etymonline.com/word/${encodeURIComponent(entry.word)}`}
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  Full entry on Etymonline ↗
                </a>
              </div>
              <p className="sectionTitle">origin story</p>
              {entry.etymology.length > 0 ? (
                <EtymologyTimeline stages={entry.etymology} />
              ) : (
                <p className="noEtymology">
                  Etymology isn't available for this word yet — it's outside the curated collection.
                  Use the link above to look it up on Etymonline instead.
                </p>
              )}

              <div className="divider" />

              <div className="related">
                <span className="relatedLabel">related</span>
                {entry.related.length > 0 ? (
                  entry.related.map((w, i) => (
                    <React.Fragment key={w}>
                      <button
                        className={WORD_LIST.includes(w) ? "relatedWord isLink" : "relatedWord"}
                        onClick={() => WORD_LIST.includes(w) && go(w)}
                      >
                        {w}
                      </button>
                      {i < entry.related.length - 1 && <span className="relatedComma">,</span>}
                    </React.Fragment>
                  ))
                ) : (
                  <span className="noRelated">No related forms on record for this word yet.</span>
                )}
              </div>

              <div className="divider" />
            </article>
          )}
        </section>
      </main>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,500;0,600;1,500;1,600&family=Inter:wght@400;500;600&family=Bodoni+Moda:ital,wght@0,400;0,600;1,500&family=Petit+Formal+Script&display=swap');
        @font-face {
          font-family: 'Louize';
          src: url(data:font/otf;base64,) format('opentype');
          font-weight: 400 600;
          font-style: normal;
          font-display: swap;
        }
        @font-face {
          font-family: 'Louize';
          src: url(data:font/otf;base64,) format('opentype');
          font-weight: 400 600;
          font-style: italic;
          font-display: swap;
        }
        @font-face {
          font-family: 'Madelinette';
          src: url(data:font/otf;base64,) format('opentype');
          font-weight: 400;
          font-style: normal;
          font-display: swap;
        }


        *{ box-sizing:border-box; }
        html, body{ margin:0; padding:0; }
        body{ background:#F8F1E2; }
        #root{ min-height:100vh; }
        .page{
          min-height:100vh; background:#F8F1E2; color:#2B2A28;
          font-family:'Inter', sans-serif; padding:0 24px 0;
          position:relative; overflow-x:hidden;
          display:flex; flex-direction:column;
        }
        .grain{
          position:fixed; inset:0; pointer-events:none; z-index:0; opacity:0.5;
          mix-blend-mode:multiply;
          background-image:
            radial-gradient(rgba(150,138,112,0.10) 0.6px, transparent 0.6px),
            radial-gradient(rgba(150,138,112,0.07) 0.6px, transparent 0.6px);
          background-size: 3px 3px, 5px 5px;
          background-position: 0 0, 1.5px 1.5px;
        }
        .header, .dayStrip, .layout, .stripeBar{ position:relative; z-index:1; }
        .stripeBar{
          height:14px;
          width:100vw;
          position:relative;
          left:50%;
          right:50%;
          margin-left:-50vw;
          margin-right:-50vw;
          background: repeating-linear-gradient(
            90deg,
            rgba(150,162,180,0.55) 0px, rgba(150,162,180,0.55) 22px,
            rgba(150,162,180,0.85) 22px, rgba(150,162,180,0.85) 44px
          );
        }
        .stripeBar.top{ margin-bottom:44px; }
        .stripeBar.bottom{ margin-top:0; }
        .header{
          max-width:720px; margin:36px auto 8px; display:flex; align-items:center;
          justify-content:space-between; gap:20px; flex-wrap:wrap;
        }
        .brand{
          font-family:'Madelinette', 'Petit Formal Script', cursive; font-size:44px; color:#6E7580;
          line-height:1; display:inline-block; padding-left:14px;
        }
        @media (max-width: 380px){ .brand{ font-size:36px; } }
        .searchForm{ position:relative; }
        .searchForm input{
          font-family:'Inter', sans-serif; font-size:14px; padding:9px 4px;
          width:200px; border:none; border-bottom:1px solid #C9BFAF; background:transparent;
          color:#2B2A28; outline:none;
        }
        .searchForm input::placeholder{ color:#A79E8F; }
        .searchForm input:focus{ border-bottom-color:#96A2B4; }
        .suggest{
          position:absolute; top:38px; left:0; right:0; background:#FFFFFF;
          border:1px solid #EAE3D6; list-style:none; margin:0; padding:4px 0; border-radius:4px;
          box-shadow:0 8px 20px rgba(43,42,40,0.08); z-index:10;
        }
        .suggest button{
          width:100%; text-align:left; background:none; border:none; padding:8px 14px;
          font-family:'Inter', sans-serif; font-size:14px; cursor:pointer; color:#2B2A28;
        }
        .suggest button:hover{ background:#FAF3EE; color:#96A2B4; }

        .dayStrip{
          max-width:720px; margin:0 auto; padding-top:20px; border-top:1px solid #EAE3D6;
          display:flex; align-items:baseline; gap:8px; flex-wrap:wrap;
          font-family:'Inter', sans-serif; font-size:13px; color:#8A8274;
        }
        .dayStripLabel{ text-transform:uppercase; letter-spacing:0.08em; font-size:11px; }
        .dayStripWord{
          background:none; border:none; cursor:pointer; padding:0; font-family:'Louize', 'Bodoni Moda', serif;
          font-style:italic; font-weight:600; font-size:17px; color:#96A2B4;
        }
        .dayStripWord:hover{ text-decoration:underline; }
        .dayStripDot{ color:#C9BFAF; }
        .dayStripDef{ font-family:'Cormorant Garamond', serif; font-size:15px; color:#8A8274; }

        .sectionDivider{ max-width:720px; margin:40px auto; height:1px; background:#EAE3D6; }
        .layout{
          max-width:720px; margin:0 auto; display:block;
          flex:1 0 auto; padding-bottom:64px;
        }

        .entry{ }
        .pos{
          font-family:'Inter', sans-serif; font-size:11px; letter-spacing:0.1em; text-transform:uppercase;
          color:#8B9A7C; margin:0 0 6px;
        }
        .entry h1{
          font-family:'Louize', 'Bodoni Moda', serif; font-weight:600; font-size:clamp(42px,7vw,64px);
          margin:0; line-height:1.02; color:#2B2A28;
        }
        .ipa{
          font-family:'Inter', sans-serif; font-size:14px; color:#A79E8F; margin:10px 0 28px;
          display:flex; align-items:center; gap:10px;
        }
        .playBtn{
          display:inline-flex; align-items:center; justify-content:center;
          width:26px; height:26px; border-radius:50%; border:1px solid #96A2B4;
          background:transparent; color:#96A2B4; cursor:pointer; padding:0; flex-shrink:0;
          transition:all .15s ease;
        }
        .playBtn:hover{ background:#96A2B4; border-color:#96A2B4; color:#FFFFFF; }
        .playBtn svg{ margin-left:1px; }

        .defs{ margin:0 0 48px; padding-left:0; list-style-position:inside; font-family:'Cormorant Garamond', serif; font-size:19px; line-height:1.7; color:#3A362F; }
        .defs li{ margin-bottom:10px; }
        .defs li::marker{ color:#96A2B4; }
        .apiNote{
          font-family:'Inter', sans-serif; font-size:11.5px; color:#A79E8F; margin:-14px 0 28px;
          letter-spacing:0.02em;
        }
        .noEtymology{
          font-family:'Cormorant Garamond', serif; font-style:italic; font-size:16.5px; color:#A79E8F; margin:4px 0 0;
        }
        .noRelated{
          font-family:'Cormorant Garamond', serif; font-style:italic; font-size:15px; color:#A79E8F;
        }

        .synonyms{ margin:0 0 48px; }
        .synonymsHead{
          display:flex; align-items:baseline; justify-content:flex-start; gap:10px;
          flex-wrap:wrap; margin-bottom:10px;
        }
        .synonymsLabel{
          display:block; font-family:'Inter', sans-serif; font-size:11px; letter-spacing:0.1em;
          text-transform:uppercase; color:#8A8274;
        }
        .externalLink{
          font-family:'Cormorant Garamond', serif; font-style:italic; font-size:14px; color:#96A2B4;
          text-decoration:none; border-bottom:1px solid transparent; transition:all .15s ease; white-space:nowrap;
        }
        .externalLink:hover{ color:#6E7580; border-bottom-color:#6E7580; }
        .chips{ display:flex; flex-wrap:wrap; gap:8px; }
        .chip{
          font-family:'Cormorant Garamond', serif; font-style:italic; font-size:15px;
          color:#5C6B4F; background:rgba(156,152,125,0.14); border:1px solid rgba(156,152,125,0.35);
          border-radius:20px; padding:5px 14px; cursor:default; transition:all .15s ease;
        }
        .chip.isLink{ cursor:pointer; }
        .chip.isLink:hover{ background:rgba(150,162,180,0.22); border-color:#96A2B4; color:#3A4048; }
        .noSynonyms{ font-family:'Cormorant Garamond', serif; font-style:italic; font-size:15.5px; color:#A79E8F; margin:0; }

        .practice{ margin:0; }
        .practiceLabel{
          display:block; font-family:'Inter', sans-serif; font-size:11px; letter-spacing:0.1em;
          text-transform:uppercase; color:#8A8274; margin-bottom:10px;
        }
        .example{
          font-family:'Cormorant Garamond', serif; font-style:italic; font-size:21px; line-height:1.5;
          color:#5C554A; margin:0; padding-left:2px;
        }
        .exampleMark{ color:#96A2B4; font-size:26px; vertical-align:-2px; }

        .divider{ height:1px; background:#EAE3D6; margin:48px 0; }

        .etymologyHead{
          display:flex; align-items:baseline; justify-content:flex-start; gap:10px;
          flex-wrap:wrap;
        }
        .etymologyHeading{
          font-family:'Louize', 'Bodoni Moda', serif; font-style:italic; font-weight:600;
          font-size:28px; color:#2B2A28; margin:0 0 16px;
        }
        .sectionTitle{
          font-family:'Inter', sans-serif; font-weight:600; font-size:11px; letter-spacing:0.1em;
          text-transform:uppercase; color:#8A8274; margin:0 0 20px;
        }

        .related{ margin-top:36px; font-size:14px; color:#8A8274; }
        .relatedLabel{ text-transform:uppercase; letter-spacing:0.08em; font-size:11px; margin-right:10px; }
        .relatedWord{ background:none; border:none; padding:0; font:inherit; color:#5C554A; cursor:default; }
        .relatedWord.isLink{ cursor:pointer; color:#96A2B4; }
        .relatedWord.isLink:hover{ text-decoration:underline; }
        .relatedComma{ margin-right:6px; color:#8A8274; }

        .empty{ padding:48px 0; }
        .emptyTitle{ font-family:'Louize', 'Bodoni Moda', serif; font-style:italic; font-size:26px; margin:0 0 8px; }
        .emptyBody{ font-family:'Cormorant Garamond', serif; font-size:17px; color:#8A8274; margin:0; }
      `}</style>
      <div className="stripeBar bottom" aria-hidden="true" />
    </div>
  );
}
